			ctx.SetContentType("application/json; charset=utf-8")
			ctx.SetStatusCode(fasthttp.StatusBadGateway)
			_ = json.NewEncoder(ctx).Encode(PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", res.StatusCode())})
