// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil // EOF is not an error here
			}
			return
		case html.StartTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				// Get the next text token as title
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(string(tokenizer.Text()))
				}
			} else if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = strings.TrimSpace(attr.Val)
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		case html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "meta" {
				var name, content string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = strings.TrimSpace(attr.Val)
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}
	}
}

