package main

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

const (
	maxBodySize           = 1 * 1024 * 1024 // 1 MB maximum body size to parse
	maxRedirectCounts     = 10
	lookupTimeout         = 5 * time.Second
)

var (
	privateIPv4Networks = []net.IPNet{
		// 10.0.0.0/8
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		// 172.16.0.0/12
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		// 192.168.0.0/16
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
	}
	// IPv6 link-local: fe80::/10
	linkLocalIPv6Network = net.IPNet{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)}
	// IPv6 unique local: fc00::/7
	uniqueLocalIPv6Network = net.IPNet{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)}
	// IPv4 link-local: 169.254.0.0/16
	linkLocalIPv4Network = net.IPNet{IP: net.ParseIP("169.254.0.0"), Mask: net.CIDRMask(16, 32)}
)

// isDisallowedIP checks if an IP address is in a disallowed range (loopback, private, link-local, etc.)
func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Check loopback, unspecified, multicast
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsMulticast() {
		return true
	}
	// Check IPv4 private ranges
	if ipv4 := ip.To4(); ipv4 != nil {
		for _, network := range privateIPv4Networks {
			if network.Contains(ipv4) {
				return true
			}
		}
		// Check IPv4 link-local
		if linkLocalIPv4Network.Contains(ipv4) {
			return true
		}
	} else {
		// IPv6 checks
		if linkLocalIPv6Network.Contains(ip) || uniqueLocalIPv6Network.Contains(ip) {
			return true
		}
	}
	return false
}

// safeDial is a custom dial function that checks for disallowed IPs and ports before connecting
func safeDial(addr string) (net.Conn, error) {
	// Split host and port
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Restrict ports to 80 (HTTP) and 443 (HTTPS)
	if port != "80" && port != "443" {
		return nil, fmt.Errorf("disallowed port: %s", port)
	}

	// Resolve host to IP addresses with timeout
	ctx, cancel := context.WithTimeout(context.Background(), lookupTimeout)
	defer cancel()
	resolver := net.Resolver{}
	ips, err := resolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Check each resolved IP
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return nil, fmt.Errorf("disallowed IP address: %s", ip.String())
		}
	}

	// All checks passed, use the default dual-stack dialer
	return fasthttp.DialDualStack(addr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client with safe dialer and timeout
	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Read body with limit to prevent OOM
	limitedReader := io.LimitReader(bytes.NewReader(res.Body()), maxBodySize+1)
	bodyBytes, err := io.ReadAll(limitedReader)
	if err != nil {
		ctx.Error("Failed to read response body", fasthttp.StatusBadGateway)
		return
	}

	// Check if body exceeds maximum size
	if len(bodyBytes) > maxBodySize {
		ctx.Error("Response body too large", fasthttp.StatusBadGateway)
		return
	}

	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

