			Error:   "invalid URL: " + err.Error(),
		}
		_ = json.NewEncoder(ctx).Encode(resp)
		return
	}
	if u.Scheme!= "http" && u.Scheme!= "https" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp := PreviewResponse{
			Success: false,
			Error:   "URL must have http or https scheme",
		}
