package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// sendErrorResponse sends a JSON error response with the given status code and message.
func sendErrorResponse(ctx *fasthttp.RequestCtx, statusCode int, errMsg string) {
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")
	resp := PreviewResponse{Error: errMsg}
	// Ignore encode error as a fallback
	_ = json.NewEncoder(ctx).Encode(resp)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		sendErrorResponse(ctx, fasthttp.StatusMethodNotAllowed, "Method not allowed")
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		sendErrorResponse(ctx, fasthttp.StatusBadRequest, "Invalid JSON")
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendErrorResponse(ctx, fasthttp.StatusBadRequest, "URL is required")
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendErrorResponse(ctx, fasthttp.StatusBadRequest, "Invalid URL format")
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendErrorResponse(ctx, fasthttp.StatusBadRequest, "URL must use http or https scheme")
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		sendErrorResponse(ctx, fasthttp.StatusBadGateway, fmt.Sprintf("Failed to fetch URL: %v", err))
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		sendErrorResponse(ctx, fasthttp.StatusBadGateway, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()))
		return
	}

	// Check Content-Type is HTML
	contentType := string(res.Header.Peek("Content-Type"))
	contentTypeLower := strings.ToLower(contentType)
	if !strings.Contains(contentTypeLower, "text/html") && !strings.Contains(contentTypeLower, "application/xhtml+xml") {
		sendErrorResponse(ctx, fasthttp.StatusBadGateway, "URL does not return HTML content")
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		sendErrorResponse(ctx, fasthttp.StatusBadGateway, "Empty response body")
		return
	}

	// Limit body to 1MB to avoid parsing large files
	const maxBodySize = 1 << 20 // 1MB
	if len(bodyBytes) > maxBodySize {
		bodyBytes = bodyBytes[:maxBodySize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		sendErrorResponse(ctx, fasthttp.StatusInternalServerError, fmt.Sprintf("Failed to parse HTML: %v", err))
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		sendErrorResponse(ctx, fasthttp.StatusInternalServerError, "Failed to encode response")
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false
	var titleBuilder strings.Builder

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil
			}
			// Final trim in case title tag wasn't closed
			title = strings.TrimSpace(titleBuilder.String())
			return title, description, err

		case html.TextToken:
			if inTitle {
				titleBuilder.Write(tokenizer.Text())
			}

		case html.StartTagToken, html.SelfClosingTagToken:
			t := tokenizer.Token()
			switch t.Data {
			case "title":
				inTitle = true
			case "meta":
				var name, property, content string
				for _, attr := range t.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = attr.Val
					case "property":
						property = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if description == "" {
					if strings.EqualFold(name, "description") {
						description = strings.TrimSpace(content)
					} else if strings.EqualFold(property, "og:description") {
						description = strings.TrimSpace(content)
					}
				}
			}

		case html.EndTagToken:
			t := tokenizer.Token()
			if t.Data == "title" {
				inTitle = false
				title = strings.TrimSpace(titleBuilder.String())
			}
		}
	}
}

