	if err != nil {
		sendError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Send success response
	sendJSONResponse(ctx, PreviewResponse{
		Title:       title,
		Description: description,
	}, fasthttp.StatusOK)
}

