// isRestrictedIP checks if an IP address is in a restricted range
func isRestrictedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Check standard restricted types
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsMulticast() || ip.IsUnspecified() {
		return true
	}
	// Check private networks (including IPv6 ULA)
	if ip.IsPrivate() {
		return true
	}
	// Check CG-NAT shared address space (100.64.0.0/10)
	cgNAT := &net.IPNet{
		IP:   net.ParseIP("100.64.0.0"),
		Mask: net.CIDRMask(10, 32),
	}
	if cgNAT.Contains(ip) {
		return true
	}
	return false
}

// safeDial is a custom dial function that validates IP addresses before connecting
func safeDial(addr string) (net.Conn, error) {
	// Split host and port
	host, port, err := net.SplitHostPort(addr)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Resolve host to IP addresses
	ips, err := net.LookupIP(host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Filter out restricted IPs
	var allowedIPs []net.IP
	for _, ip := range ips {
		if!isRestrictedIP(ip) {
			allowedIPs = append(allowedIPs, ip)
		}
	}
	if len(allowedIPs) == 0 {
		return nil, fmt.Errorf("no allowed IP addresses for host")
	}

	// Separate IPv4 and IPv6 to prefer IPv4 first
	var v4IPs, v6IPs []net.IP
	for _, ip := range allowedIPs {
		if ip.To4()!= nil {
			v4IPs = append(v4IPs, ip)
		} else {
			v6IPs = append(v6IPs, ip)
		}
	}
	dialIPs := append(v4IPs, v6IPs...)

	// Try each allowed IP with a timeout
	var lastErr error
	for _, ip := range dialIPs {
		var dialAddr string
		if ip.To4()!= nil {
			dialAddr = net.JoinHostPort(ip.String(), port)
		} else {
			dialAddr = net.JoinHostPort("["+ip.String()+"]", port)
		}

		conn, err := net.DialTimeout("tcp", dialAddr, 5*time.Second)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to dial any allowed IP: %w", lastErr)
}

// getTextContent extracts all text content from an HTML node
func getTextContent(n *html.Node) string {
	var buf bytes.Buffer
	var f func(*html.Node)
	f = func(c *html.Node) {
		if c.Type == html.TextNode {
			buf.WriteString(c.Data)
		}
		for child := c.FirstChild; child!= nil; child = child.NextSibling {
			f(child)
		}
	}
	f(n)
	return strings.TrimSpace(buf.String())
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err!= nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				title = getTextContent(n)
			case "meta":
				name := ""
				content := ""
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = strings.TrimSpace(content)
				}
			}
		}
		// Recurse into children
		for c := n.FirstChild; c!= nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

