		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON request body"})
		return
	}

	// Validate URL presence
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL field is required"})
		return
	}

	// Initialize fasthttp client with required Dial setting
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Acquire request/response objects
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(httpReq)
	defer fasthttp.ReleaseResponse(httpResp)

	// Configure the outgoing request
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("fasthttp-url-preview/1.0")

