// PreviewRequest represents the incoming JSON request structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response structure
type PreviewResponse struct {
	Success     bool   `json:"success"`
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// sendJSONResponse helper to send standardized JSON responses
func sendJSONResponse(ctx *fasthttp.RequestCtx, success bool, title, description, errMsg string) {
	ctx.SetContentType("application/json; charset=utf-8")
	resp := PreviewResponse{
		Success:     success,
		Title:       title,
		Description: description,
		Error:       errMsg,
	}
	if err := json.NewEncoder(ctx).Encode(resp); err!= nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.WriteString(`{"success":false,"error":"failed to encode response"}`)
	}
}

// extractTitleAndDescription parses HTML to extract page title and meta description
func extractTitleAndDescription(body []byte) (title, description string) {
	tokenizer := html.NewTokenizer(bytes.NewReader(body))
	inTitle := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return
		case html.StartTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tagStr := strings.ToLower(string(tagName))

			if tagStr == "title" {
				inTitle = true
			} else if tagStr == "meta" {
				var name, content string
				if hasAttr {
					for {
						key, val, moreAttr := tokenizer.TagAttr()
						keyStr := strings.ToLower(string(key))
						switch keyStr {
						case "name":
							name = string(val)
						case "content":
							content = string(val)
						}
						if!moreAttr {
							break
						}
					}
				}
				if strings.EqualFold(name, "description") && description == "" {
					description = content
				}
			}
		case html.TextToken:
			if inTitle {
				title = strings.TrimSpace(string(tokenizer.Text()))
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			if strings.EqualFold(string(tagName), "title") {
				inTitle = false
			}
		}
	}
}

// FetchURLPreview is the fasthttp handler to fetch and parse URL previews
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Validate request method is POST
	if!bytes.Equal(ctx.Method(), []byte(fasthttp.MethodPost)) {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		sendJSONResponse(ctx, false, "", "", "method not allowed, use POST")
		return
	}

	// Parse incoming JSON request
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err!= nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, false, "", "", fmt.Sprintf("invalid request body: %v", err))
		return
	}

	// Clean and validate the input URL
	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, false, "", "", "url is required")
		return
	}

	parsedURL, err := url.Parse(req.URL)
	if err!= nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, false, "", "", fmt.Sprintf("invalid url: %v", err))
		return
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, false, "", "", "url must have http or https scheme")
		return
	}

	if parsedURL.Host == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, false, "", "", "url must have a valid host")
		return
	}

	// Configure fasthttp client with DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Acquire request and response objects
	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Setup the HTTP request
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	// Set a user-agent to avoid being blocked by basic anti-bot checks
	httpReq.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewFetcher/1.0; +https://example.com/bot)")

	// Fetch the URL with redirect following (max 10 redirects)
	err = client.DoRedirects(httpReq, httpResp, 10)
	if err!= nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		sendJSONResponse(ctx, false, "", "", fmt.Sprintf("failed to fetch url: %v", err))
		return
	}

	// Extract title and description from response body
	title, description := extractTitleAndDescription(httpResp.Body())

	// Send successful response
	sendJSONResponse(ctx, true, title, description, "")
}

func main() {
	// Start the fasthttp server on port 8080
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err!= nil {
		panic(fmt.Sprintf("failed to start server: %v", err))
	}
}

