func writeSuccess(ctx *fasthttp.RequestCtx, title, description string) {
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	resp := PreviewSuccessResponse{
		Title:       title,
		Description: description,
	}
	b, err := json.Marshal(resp)
	if err!= nil {
		writeError(ctx, fasthttp.StatusInternalServerError, "failed to marshal success response")
		return
	}
	_, _ = ctx.Write(b)
}

func parseMetaTag(t html.Token, description *string) {
	var name, content string
	for _, attr := range t.Attr {
		key := strings.ToLower(attr.Key)
		if key == "name" {
			name = strings.ToLower(attr.Val)
		} else if key == "content" {
			content = attr.Val
		}
	}
	if name == "description" && *description == "" {
		*description = content
	}
}

func extractPreview(r io.Reader) (title string, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inHead := false
	inTitle := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil
			}
			return
		case html.StartTagToken:
			t := tokenizer.Token()
			switch t.Data {
			case "head":
				inHead = true
			case "title":
				if inHead {
					inTitle = true
				}
			case "meta":
				if inHead {
					parseMetaTag(t, &description)
				}
			}
		case html.SelfClosingTagToken:
			t := tokenizer.Token()
			if inHead && t.Data == "meta" {
				parseMetaTag(t, &description)
			}
		case html.EndTagToken:
			t := tokenizer.Token()
			switch t.Data {
			case "head":
