func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if!ctx.IsPost() {
		writeError(ctx, fasthttp.StatusMethodNotAllowed, "only POST requests are allowed")
		return
	}

	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err!= nil {
		writeError(ctx, fasthttp.StatusBadRequest, "invalid JSON request body")
		return
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		writeError(ctx, fasthttp.StatusBadRequest, "url field is required")
		return
	}

	parsedURL, err := url.Parse(req.URL)
	if err!= nil {
		writeError(ctx, fasthttp.StatusBadRequest, "invalid URL format")
		return
	}
	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		writeError(ctx, fasthttp.StatusBadRequest, "URL must use http or https scheme")
		return
	}

	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         30 * time.Second,
		WriteTimeout:        30 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
	}

	reqHTTP := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(reqHTTP)
	respHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(respHTTP)

	reqHTTP.SetRequestURI(req.URL)
	reqHTTP.Header.SetMethod(fasthttp.MethodGet)
	reqHTTP.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewFetcher/1.0; +https://example.com/bot)")

	err = client.DoRedirects(reqHTTP, respHTTP, 10)
	if err!= nil {
		log.Printf("Failed to fetch URL %s: %v", req.URL, err)
		writeError(ctx, fasthttp.StatusBadGateway, "failed to fetch the provided URL")
		return
	}

	statusCode := respHTTP.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		log.Printf("URL %s returned non-2xx status: %d", req.URL, statusCode)
		writeError(ctx, fasthttp.StatusBadGateway, "received non-success status code from URL")
		return
	}

	contentType := strings.ToLower(string(respHTTP.Header.ContentType()))
	if!strings.HasPrefix(contentType, "text/html") {
		writeError(ctx, fasthttp.StatusBadRequest, "URL does not return HTML content")
		return
	}

	bodyReader := io.LimitReader(bytes.NewReader(respHTTP.Body()), 1024*1024)
	title, description, err := extractPreview(bodyReader)
	if err!= nil {
		log.Printf("Non-critical HTML parsing error for URL %s: %v", req.URL, err)
	}

	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	writeSuccess(ctx, title, description)
}

func main() {
	log.Println("Starting URL preview server on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err!= nil {
