// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false
	inHead := true // Stop parsing once we leave the head section

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// Return what we have on EOF, otherwise return the error
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil
			}
			title = strings.TrimSpace(title)
			return
		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tagStr := string(tagName)
			if !inHead {
				continue
			}
			switch tagStr {
			case "body":
				inHead = false
			case "title":
				inTitle = true
			case "meta":
				if hasAttr {
					var name, content string
					for {
						attrKey, attrVal, moreAttr := tokenizer.TagAttr()
						keyStr := strings.ToLower(string(attrKey))
						valStr := string(attrVal)
						switch keyStr {
						case "name":
							name = strings.ToLower(valStr)
						case "content":
							content = valStr
						}
						if !moreAttr {
							break
						}
					}
					if name == "description" && content != "" {
						description = content
					}
				}
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			tagStr := string(tagName)
			if tagStr == "title" {
				inTitle = false
			} else if tagStr == "head" {
				inHead = false
			}
		case html.TextToken:
			if inTitle && inHead {
				title += string(tokenizer.Text())
			}
		}

		// Exit early if we're out of the head and not in title
		if !inHead && !inTitle {
			break
		}
	}

	title = strings.TrimSpace(title)
	return
}

