import (
	"bytes"
	"encoding/json"
	"fmt"
	"log"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Success     bool   `json:"success"`
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

func getTextContent(n *html.Node) string {
	var buf bytes.Buffer
	var collect func(*html.Node)
	collect = func(node *html.Node) {
		if node.Type == html.TextNode {
			buf.WriteString(node.Data)
		}
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			collect(c)
		}
	}
	collect(n)
	return strings.TrimSpace(buf.String())
}

func extractMeta(n *html.Node) (title, desc string) {
	if n.Type == html.ElementNode {
		if n.Data == "title" {
			title = getTextContent(n)
		} else if n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" {
					name = strings.ToLower(attr.Val)
				} else if attr.Key == "content" {
					content = attr.Val
				}
			}
			if name == "description" {
				desc = strings.TrimSpace(content)
			}
		}
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		t, d := extractMeta(c)
		if title == "" {
			title = t
		}
		if desc == "" {
			desc = d
		}
	}
	return title, desc
}

func sendJSONResponse(ctx *fasthttp.RequestCtx, resp PreviewResponse, statusCode int) {
	ctx.SetStatusCode(statusCode)
	ctx.Response.Header.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Response.Header.SetContentType("application/json")
		ctx.SetBodyString(`{"success":false,"error":"Failed to encode response"}`)
	}
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse request body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendJSONResponse(ctx, PreviewResponse{
			Success: false,
			Error:   "Invalid request body",
		}, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL presence
	if req.URL == "" {
		sendJSONResponse(ctx, PreviewResponse{
			Success: false,
			Error:   "URL is required",
		}, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		sendJSONResponse(ctx, PreviewResponse{
			Success: false,
			Error:   "Invalid URL: must be a valid HTTP/HTTPS URL",
		}, fasthttp.StatusBadRequest)
		return
	}

	// Set up fasthttp client with required Dial configuration
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Acquire request and response objects
	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Configure request
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)

	// Channel to handle fetch result
	type fetchResult struct {
		err error
	}
	resultChan := make(chan fetchResult, 1)

	// Perform fetch in goroutine
	go func() {
		// Follow up to 10 redirects
		err := client.DoRedirects(httpReq, httpResp, 10)
		resultChan <- fetchResult{err: err}
	}()

	// Wait for result or timeout
	select {
	case res := <-resultChan:
		if res.err != nil {
			sendJSONResponse(ctx, PreviewResponse{
				Success: false,
				Error:   fmt.Sprintf("Failed to fetch URL: %v", res.err),
			}, fasthttp.StatusInternalServerError)
			return
		}
	case <-time.After(3 * time.Second):
		sendJSONResponse(ctx, PreviewResponse{
			Success: false,
			Error:   "Request timed out while fetching URL",
		}, fasthttp.StatusGatewayTimeout)
		return
	}

	// Parse HTML
	doc, err := html.Parse(bytes.NewReader(httpResp.Body()))
	if err != nil {
		sendJSONResponse(ctx, PreviewResponse{
			Success: false,
			Error:   "Failed to parse HTML content",
		}, fasthttp.StatusInternalServerError)
		return
	}

	// Extract meta data
	title, description := extractMeta(doc)

	// Send success response
	sendJSONResponse(ctx, PreviewResponse{
		Success:     true,
		Title:       title,
		Description: description,
	}, fasthttp.StatusOK)
}

func main() {
	log.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

