package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/url"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func getTextContent(n *html.Node) string {
	var buf strings.Builder
	var collect func(*html.Node)
	collect = func(c *html.Node) {
		if c.Type == html.TextNode {
			buf.WriteString(c.Data)
		}
		for child := c.FirstChild; child!= nil; child = child.NextSibling {
			collect(child)
		}
	}
	collect(n)
	return strings.TrimSpace(buf.String())
}

func parseHTML(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err!= nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				title = getTextContent(n)
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c!= nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)
	return title, description, nil
}

func sendJSONResponse(ctx *fasthttp.RequestCtx, resp PreviewResponse, statusCode int) {
	ctx.SetStatusCode(statusCode)
	ctx.Response.Header.SetContentType("application/json")
	_ = json.NewEncoder(ctx).Encode(resp)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Check if request method is POST
	if!bytes.Equal(ctx.Method(), []byte(fasthttp.MethodPost)) {
		ctx.Response.Header.Set(fasthttp.HeaderAllow, fasthttp.MethodPost)
		sendJSONResponse(ctx, PreviewResponse{Error: "only POST requests are allowed"}, fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse request body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err!= nil {
		sendJSONResponse(ctx, PreviewResponse{Error: "invalid request body: " + err.Error()}, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if req.URL == "" {
		sendJSONResponse(ctx, PreviewResponse{Error: "url field is required"}, fasthttp.StatusBadRequest)
		return
	}
	parsedURL, err := url.Parse(req.URL)
	if err!= nil || (parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https") {
		sendJSONResponse(ctx, PreviewResponse{Error: "invalid URL: must be a valid HTTP/HTTPS URL"}, fasthttp.StatusBadRequest)
		return
	}

	// Create fasthttp client with DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Acquire request and response objects
	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Configure request
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("URL-Preview-Fetcher/1.0 (+https://example.com)")

	// Fetch URL with redirect following
	err = client.DoRedirects(httpReq, httpResp, 10)
	if err!= nil {
		sendJSONResponse(ctx, PreviewResponse{Error: "failed to fetch URL: " + err.Error()}, fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML content
	bodyReader := bytes.NewReader(httpResp.Body())
	title, description, err := parseHTML(bodyReader)
	if err!= nil {
		sendJSONResponse(ctx, PreviewResponse{Error: "failed to parse HTML content: " + err.Error()}, fasthttp.StatusUnprocessableEntity)
		return
	}

	// Send successful response
	sendJSONResponse(ctx, PreviewResponse{
		Title:       title,
		Description: description,
	}, fasthttp.StatusOK)
}

func main() {
	fmt.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err!= nil {
		panic(fmt.Sprintf("Server failed to start: %v", err))
	}
}

