			return nil, fmt.Errorf("disallowed IP address: %s", ip.String())
		}
	}

	// Pick the first resolved IP to avoid DNS rebinding
	var dialIP net.IP
	for _, ip := range ips {
		dialIP = ip
		break
	}
	if dialIP == nil {
		return nil, fmt.Errorf("no valid IP addresses found for %s", host)
	}

	dialAddr := net.JoinHostPort(dialIP.String(), port)
	return fasthttp.DialDualStack(dialAddr)
}

