// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false
	inHead := true // Stop parsing once we leave the head section

	for inHead {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			// End of input, return what we have
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil
			}
			return strings.TrimSpace(title), strings.TrimSpace(description), err
		case html.StartTagToken:
			t := tokenizer.Token()
			tagName := strings.ToLower(t.Data)
			switch tagName {
			case "title":
				inTitle = true
			case "meta":
				name, content := extractMetaAttrs(t.Attr)
				if name == "description" && description == "" {
					description = content
				}
			case "body":
				// Entering body, head is done
				inHead = false
			}
		case html.EndTagToken:
			t := tokenizer.Token()
			tagName := strings.ToLower(t.Data)
			switch tagName {
			case "title":
				inTitle = false
			case "head":
				inHead = false
			}
		case html.TextToken:
			if inTitle {
				title += string(tokenizer.Text())
			}
		case html.SelfClosingTagToken:
			t := tokenizer.Token()
			if strings.ToLower(t.Data) == "meta" {
				name, content := extractMetaAttrs(t.Attr)
				if name == "description" && description == "" {
					description = content
				}
			}
		}

		// Early exit if we have both title and description
		if title != "" && description != "" {
			break
		}
	}

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

// extractMetaAttrs extracts name (lowercase) and content attributes from meta tag attributes
func extractMetaAttrs(attrs []html.Attribute) (name, content string) {
	for _, attr := range attrs {
		attrKey := strings.ToLower(attr.Key)
		switch attrKey {
		case "name":
			name = strings.ToLower(attr.Val)
		case "content":
			content = attr.Val
		}
	}
	return name, content
}

