// isForbiddenIP checks if an IP address is in a forbidden range (loopback, private, link-local, unspecified)
func isForbiddenIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	// Block loopback addresses
	if ip.IsLoopback() {
		return true
	}
	// Block private addresses (IPv4: 10/8, 172.16/12, 192.168/16; IPv6 ULA: fc00::/7)
	if ip.IsPrivate() {
		return true
	}
	// Block link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Block unspecified addresses (0.0.0.0, ::)
	if ip.IsUnspecified() {
		return true
	}
	return false
}

// safeDial is a custom dial function that validates IP addresses before connecting to prevent SSRF
func safeDial(addr string) (net.Conn, error) {
	// Split host and port
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Create a context with timeout for DNS resolution and dialing
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Resolve host to IP addresses using context for timeout
	resolver := &net.Resolver{}
	ips, err := resolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Filter out forbidden IP addresses
	var allowedIPs []net.IP
	for _, ip := range ips {
		if !isForbiddenIP(ip) {
			allowedIPs = append(allowedIPs, ip)
		}
	}

	if len(allowedIPs) == 0 {
		return nil, errors.New("no allowed IP addresses for host")
	}

	// Try to dial each allowed IP address
	var firstErr error
	dialer := &net.Dialer{
		Timeout: 5 * time.Second,
	}
	for _, ip := range allowedIPs {
		ipAddr := net.JoinHostPort(ip.String(), port)
		conn, err := dialer.DialContext(ctx, "tcp", ipAddr)
		if err == nil {
			return conn, nil
		}
		if firstErr == nil {
			firstErr = err
		}
	}

	return nil, fmt.Errorf("failed to dial any allowed IP: %w", firstErr)
}

