	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Acquire pooled request/response objects
	httpReq := fasthttp.AcquireRequest()
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(httpReq)
	defer fasthttp.ReleaseResponse(httpResp)

	// Prepare request
	httpReq.SetRequestURI(reqBody.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("URL-Preview-Fetcher/1.0 (+https://example.com)")

	// Execute request with redirect following and timeout
	errChan := make(chan error, 1)
	go func() {
		errChan <- client.DoRedirects(httpReq, httpResp, 10)
	}()

	var err error
	select {
	case err = <-errChan:
		// Request completed
	case <-time.After(3 * time.Second):
		err = fmt.Errorf("request timed out after 3 seconds")
	}

	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{
			Success: false,
			Error:   "failed to fetch URL: " + err.Error(),
		})
		return
	}

	// Parse HTML for title and meta description
	var title, description string
	tokenizer := html.NewTokenizer(bytes.NewReader(httpResp.Body()))

parseLoop:
	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// End of document or error, exit loop
			break parseLoop
		case html.StartTagToken:
			token := tokenizer.Token()
			switch token.Data {
			case "title":
				// Extract title text until end tag
				var titleBuf bytes.Buffer
				for {
					innerTokenType := tokenizer.Next()
					if innerTokenType == html.ErrorToken || innerTokenType == html.EndTagToken {
						break
					}
					if innerTokenType == html.TextToken {
						titleBuf.Write(tokenizer.Text())
					}
				}
				title = strings.TrimSpace(titleBuf.String())
			case "meta":
				// Check for description meta tag
				var nameAttr, contentAttr string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						nameAttr = attr.Val
					case "content":
						contentAttr = attr.Val
					}
				}
				if strings.EqualFold(nameAttr, "description") {
					description = strings.TrimSpace(contentAttr)
				}
			}
		case html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "meta" {
				// Check for description meta tag (self-closing)
				var nameAttr, contentAttr string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						nameAttr = attr.Val
					case "content":
						contentAttr = attr.Val
					}
				}
				if strings.EqualFold(nameAttr, "description") {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}
	}

	// Send successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	_ = json.NewEncoder(ctx).Encode(PreviewResponse{
		Success:     true,
		Title:       title,
		Description: description,
	})
