// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	var titleBuf strings.Builder
	inTitle := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			// End of document or error. EOF is not an error here.
			if tokenizer.Err() == io.EOF {
				return strings.TrimSpace(titleBuf.String()), description, nil
			}
			return "", "", tokenizer.Err()

		case html.TextToken:
			if inTitle {
				titleBuf.Write(tokenizer.Text())
			}

		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tName := strings.ToLower(string(tagName))

			if tName == "title" {
				inTitle = true
			} else if tName == "meta" {
				var nameAttr, contentAttr string
				for hasAttr {
					attrKey, attrVal, hasMore := tokenizer.TagAttr()
					hasAttr = hasMore
					key := strings.ToLower(string(attrKey))
					switch key {
					case "name":
						nameAttr = strings.ToLower(string(attrVal))
					case "content":
						contentAttr = string(attrVal)
					}
				}
				// Set description if we found name="description" with content
				if nameAttr == "description" && contentAttr != "" {
					description = contentAttr
				}
			}

		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			tName := strings.ToLower(string(tagName))
			if tName == "title" {
				inTitle = false
			} else if tName == "head" {
				// Early exit once head is closed, as title/meta are in head
				return strings.TrimSpace(titleBuf.String()), description, nil
			}
		}
	}
}

