var blockedIPNets = []*net.IPNet{
	// Loopback addresses
	mustParseCIDR("127.0.0.0/8"),
	mustParseCIDR("::1/128"),
	// Private IPv4 ranges (RFC 1918)
	mustParseCIDR("10.0.0.0/8"),
