}

func mustParseCIDR(cidr string) *net.IPNet {
	_, ipNet, err := net.ParseCIDR(cidr)
	if err != nil {
		panic(fmt.Sprintf("failed to parse CIDR %q: %v", cidr, err))
	}
	return ipNet
}

func isBlockedIP(ip net.IP) bool {
	for _, ipNet := range blockedIPNets {
		if ipNet.Contains(ip) {
			return true
		}
	}
	return false
}

func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address %q: %w", addr, err)
	}

	// Resolve host to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host %q: %w", host, err)
	}

	// Filter out blocked IPs
	var allowedIPs []net.IP
	for _, ip := range ips {
		if !isBlockedIP(ip) {
			allowedIPs = append(allowedIPs, ip)
		}
	}

	if len(allowedIPs) == 0 {
		return nil, fmt.Errorf("no allowed IP addresses for host %q", host)
	}

	// Try dialing each allowed IP
	var lastErr error
	for _, ip := range allowedIPs {
		var dialAddr string
		if ip.To4() == nil {
			// IPv6 address needs brackets
			dialAddr = fmt.Sprintf("[%s]:%s", ip.String(), port)
		} else {
			dialAddr = fmt.Sprintf("%s:%s", ip.String(), port)
		}

		// Use fasthttp's default dialer for the actual connection
		conn, err := fasthttp.Dial(dialAddr)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to dial any allowed IP: %w", lastErr)
}

