				title = getText(n)
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					switch key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

// writeJSONResponse is a helper to write JSON responses with proper content type
func writeJSONResponse(ctx *fasthttp.RequestCtx, resp PreviewResponse, statusCode int) {
	ctx.SetStatusCode(statusCode)
	ctx.Response.Header.SetContentType("application/json")
	_ = json.NewEncoder(ctx).Encode(resp)
}

// FetchURLPreview is the request handler as specified
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Validate request method is POST
	if !ctx.IsPost() {
		writeJSONResponse(ctx, PreviewResponse{Error: "only POST method is allowed"}, fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse incoming JSON request
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSONResponse(ctx, PreviewResponse{Error: "failed to parse request body: " + err.Error()}, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL presence
	if req.URL == "" {
		writeJSONResponse(ctx, PreviewResponse{Error: "url field is required"}, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL structure and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		writeJSONResponse(ctx, PreviewResponse{Error: "invalid URL format: " + err.Error()}, fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		writeJSONResponse(ctx, PreviewResponse{Error: "URL must use http or https scheme"}, fasthttp.StatusBadRequest)
		return
	}

	// Initialize fasthttp client with DialDualStack as required
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Acquire and release request/response objects to optimize memory usage
	fReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(fReq)
	fResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(fResp)

	// Configure outgoing request
	fReq.Header.SetMethod(fasthttp.MethodGet)
	fReq.SetRequestURI(req.URL)
	// Set a realistic user agent to avoid being blocked by default
	fReq.Header.Set("User-Agent", "Go-Fasthttp-URL-Preview/1.0")

	// Execute request with up to 10 redirects as required
	err = client.DoRedirects(fReq, fResp, 10)
	if err != nil {
		writeJSONResponse(ctx, PreviewResponse{Error: "failed to fetch URL: " + err.Error()}, fasthttp.StatusInternalServerError)
		return
	}

	// Extract title and description from the response HTML
	title, description, parseErr := extractPreview(strings.NewReader(string(fResp.Body())))

	// Build the final response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	if parseErr != nil {
		resp.Error = "failed to parse HTML content: " + parseErr.Error()
	}

	// Send successful response
	writeJSONResponse(ctx, resp, fasthttp.StatusOK)
}

func main() {
	// Simple router to handle only /preview endpoint
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.Response.Header.SetContentType("text/plain")
			ctx.WriteString("404 Not Found - Use POST /preview with JSON body {\"url\": \"...\"}")
		}
	}

	println("Server starting on :8080...")
	println("Send POST requests to http://localhost:8080/preview with JSON body {\"url\": \"https://example.com\"}")
	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		panic(fmt.Sprintf("Server failed to start: %v", err))
	}
}

