				if strings.EqualFold(metaName, "description") {
					description = metaContent
				}
			}

		case html.EndTagToken:
			tag, _ := tokenizer.TagName()
			if strings.ToLower(string(tag)) == "title" {
				inTitle = false
				title = strings.TrimSpace(title)
			}
