// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// Restricted networks for SSRF protection
var (
	restrictedNetworks = []net.IPNet{
		// IPv4 loopback
		{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},
		// IPv4 private networks
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
		// IPv4 link-local
		{IP: net.ParseIP("169.254.0.0"), Mask: net.CIDRMask(16, 32)},
		// IPv4 multicast
		{IP: net.ParseIP("224.0.0.0"), Mask: net.CIDRMask(4, 32)},
		// IPv4 unspecified
		{IP: net.ParseIP("0.0.0.0"), Mask: net.CIDRMask(8, 32)},
		// IPv6 loopback
		{IP: net.ParseIP("::1"), Mask: net.CIDRMask(128, 128)},
		// IPv6 ULA (unique local address)
		{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)},
		// IPv6 link-local
		{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)},
		// IPv6 multicast
		{IP: net.ParseIP("ff00::"), Mask: net.CIDRMask(8, 128)},
		// IPv6 unspecified
		{IP: net.ParseIP("::"), Mask: net.CIDRMask(128, 128)},
	}
)

// isRestrictedIP checks if an IP address is in a restricted range
func isRestrictedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	for _, network := range restrictedNetworks {
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

// restrictedDial is a custom dial function that validates IP addresses before dialing
func restrictedDial(addr string) (net.Conn, error) {
	// Split host and port
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Resolve host to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Check each IP and collect valid ones
	var validIPs []net.IP
	for _, ip := range ips {
		if !isRestrictedIP(ip) {
			validIPs = append(validIPs, ip)
		}
	}

	if len(validIPs) == 0 {
		return nil, fmt.Errorf("no valid, non-restricted IP addresses for host %s", host)
	}

	// Try to dial each valid IP until we succeed
	var lastErr error
	dialer := &net.Dialer{
		Timeout:   5 * time.Second,
		KeepAlive: 10 * time.Second,
	}
	for _, ip := range validIPs {
		ipAddr := net.JoinHostPort(ip.String(), port)
		conn, err := dialer.Dial("tcp", ipAddr)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to dial any valid IP: %w", lastErr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	const maxPostBodySize = 10 << 10 // 10KB - more than enough for a URL JSON

	// Get request body bytes
	bodyBytes := ctx.Request.Body()
	if len(bodyBytes) > maxPostBodySize {
		ctx.Error("Request body too large", fasthttp.StatusRequestEntityTooLarge)
		return
	}

	// Use a strict JSON decoder
	decoder := json.NewDecoder(bytes.NewReader(bodyBytes))
	decoder.DisallowUnknownFields()

	var req struct {
		URL string `json:"url"`
	}
	if err := decoder.Decode(&req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	// Check for extra data after JSON
	if decoder.More() {
		ctx.Error("Invalid JSON: extra data", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Host == "" {
		ctx.Error("URL must have a valid host", fasthttp.StatusBadRequest)
		return
	}

	// Configure fasthttp client with security settings
	client := &fasthttp.Client{
		Dial:                restrictedDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 1 << 20, // 1MB - enough for HTML head
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0 (+https://example.com/bot)")

	const maxRedirectCounts = 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		resp := PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json; charset=utf-8")
		_ = json.NewEncoder(ctx).Encode(resp)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		resp := PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", res.StatusCode())}
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json; charset=utf-8")
		_ = json.NewEncoder(ctx).Encode(resp)
		return
	}

	respBodyBytes := res.Body()
	if len(respBodyBytes) == 0 {
		resp := PreviewResponse{Error: "Empty response body"}
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json; charset=utf-8")
		_ = json.NewEncoder(ctx).Encode(resp)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(respBodyBytes))
	if err != nil {
		resp := PreviewResponse{Error: fmt.Sprintf("Failed to parse HTML: %v", err)}
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json; charset=utf-8")
		_ = json.NewEncoder(ctx).Encode(resp)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	_ = json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			// End of file, return collected data
			if errors.Is(tokenizer.Err(), io.EOF) {
				return title, description, nil
			}
			return "", "", tokenizer.Err()
		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			if bytes.Equal(tagName, []byte("title")) {
				inTitle = true
			} else if bytes.Equal(tagName, []byte("meta")) {
				// Extract meta tag attributes
				var nameAttr, contentAttr string
				for hasAttr {
					var attrKey, attrVal []byte
					attrKey, attrVal, hasAttr = tokenizer.TagAttr()
					if bytes.Equal(attrKey, []byte("name")) {
						nameAttr = string(bytes.ToLower(attrVal))
					} else if bytes.Equal(attrKey, []byte("content")) {
						contentAttr = string(attrVal)
					}
				}
				// Only set description if we haven't found one yet
				if nameAttr == "description" && description == "" {
					description = contentAttr
				}
			}
		case html.TextToken:
			if inTitle && title == "" {
				title = string(bytes.TrimSpace(tokenizer.Text()))
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			if bytes.Equal(tagName, []byte("title")) {
				inTitle = false
			}
			// Early exit if we have all needed data or end of head
			if (title != "" && description != "") || bytes.Equal(tagName, []byte("head")) {
				return title, description, nil
			}
		}
	}
}

