type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Success     bool   `json:"success"`
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

func getText(n *html.Node) string {
	var buf strings.Builder
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.TextNode {
			buf.WriteString(n.Data)
		}
		for c := n.FirstChild; c!= nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(n)
	return strings.TrimSpace(buf.String())
}

func parseHTMLMeta(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err!= nil {
		return "", "", err
	}
	var title string
	var description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				title = getText(n)
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = strings.TrimSpace(content)
				}
			}
		}
		for child := n.FirstChild; child!= nil; child = child.NextSibling {
			traverse(child)
		}
	}
	traverse(doc)
	return title, description, nil
}

func sendJSONResponse(ctx *fasthttp.RequestCtx, success bool, title, description, errMsg string) {
	ctx.SetContentType("application/json; charset=utf-8")
	resp := PreviewResponse{
		Success:     success,
		Title:       title,
		Description: description,
		Error:       errMsg,
	}
	if!success {
		if strings.Contains(errMsg, "invalid URL") || strings.Contains(errMsg, "invalid request") || strings.Contains(errMsg, "only POST") {
			ctx.SetStatusCode(fasthttp.StatusBadRequest)
		} else {
			ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		}
	} else {
		ctx.SetStatusCode(fasthttp.StatusOK)
	}
	_ = json.NewEncoder(ctx).Encode(resp)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if string(ctx.Method())!= fasthttp.MethodPost {
		sendJSONResponse(ctx, false, "", "", "only POST requests are allowed")
		return
	}

	var req PreviewRequest
	if err := json.Unmarshal(ctx.Request.Body(), &req); err!= nil {
		sendJSONResponse(ctx, false, "", "", "invalid request body: "+err.Error())
		return
	}

	if req.URL == "" {
		sendJSONResponse(ctx, false, "", "", "url field is required")
		return
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		sendJSONResponse(ctx, false, "", "", "invalid URL: "+err.Error())
		return
	}
	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		sendJSONResponse(ctx, false, "", "", "URL must use http or https scheme")
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Set up timeout context
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.Set("User-Agent", "fasthttp-url-preview/1.0")

	err = client.DoRedirectsCtx(reqCtx, httpReq, httpResp, 5)
	if err != nil {
		sendJSONResponse(ctx, false, "", "", "failed to fetch URL: "+err.Error())
		return
	}

	title, desc, err := parseHTMLMeta(bytes.NewReader(httpResp.Body()))
	if err != nil {
		sendJSONResponse(ctx, false, "", "", "failed to parse HTML: "+err.Error())
		return
	}

	sendJSONResponse(ctx, true, title, desc, "")
}

func main() {
	println("Server starting on :8080")
	err := fasthttp.ListenAndServe(":8080", FetchURLPreview)
	if err != nil {
		panic(err)
	}
}

